public class PowerOfTwoMaxHeap {

    private int x;
    private List<Integer> heap;

    public PowerOfTwoMaxHeap(int x) {
        this.x = x;
        this.heap = new ArrayList<>();
    }

    public void insert(int value) {
        heap.add(value);
        bubbleUp(heap.size() - 1);
    }

    public int popMax() {
        int max = heap.get(0);
        int last = heap.remove(heap.size() - 1);
        if (!heap.isEmpty()) {
            heap.set(0, last);
            bubbleDown(0);
        }
        return max;
    }

    private void bubbleUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / x;
            if (heap.get(parent) < heap.get(index)) {
                Collections.swap(heap, parent, index);
                index = parent;
            } else {
                break;
            }
        }
    }

    private void bubbleDown(int index) {
        while (true) {
            int leftChild = index * x + 1;
            if (leftChild >= heap.size()) {
                break;
            }
            int maxChild = leftChild;
            for (int i = 2; i <= x; i++) {
                int rightChild = leftChild + i - 1;
                if (rightChild < heap.size() && heap.get(rightChild) > heap.get(maxChild)) {
                    maxChild = rightChild;
                }
            }
            if (heap.get(index) < heap.get(maxChild)) {
                Collections.swap(heap, index, maxChild);
                index = maxChild;
            } else {
                break;
            }
        }
    }
}

